        /// </remarks>
        /// <param name="oBPv510CreateVRPConsentRequestRequest">Request body</param>
        /// <param name="cancellationToken">Cancellation Token to cancel the request.</param>
        /// <returns><see cref="Task"/>&lt;<see cref="IOBPv510CreateVRPConsentRequestApiResponse"/>?&gt;</returns>
        Task<IOBPv510CreateVRPConsentRequestApiResponse?> OBPv510CreateVRPConsentRequestOrDefaultAsync(OBPv510CreateVRPConsentRequestRequest oBPv510CreateVRPConsentRequestRequest, System.Threading.CancellationToken cancellationToken = default);
    }

